    {
      "keystrokes": "python3 -c \"import pandas as pd; df = pd.read_csv('/data/train_identity.csv'); dups = df[df['TransactionID'].duplicated(keep=False)]; print(dups.index.min(), dups.index.max(), dups.shape)\"\n",
