      "keystrokes": "python3 -c \"import pandas as pd; df = pd.read_csv('/data/train_identity.csv'); print(df[df['TransactionID'].duplicated(keep='first')].index.tolist()[:30])\"\n",
      "duration": 5.0
    }
  ]
