    {
      "keystrokes": "python3 -c \"import pandas as pd; df = pd.read_csv('/data/train_identity.csv'); dups = df[df['TransactionID'].duplicated(keep='first')].index.tolist(); print(len(dups), min(dups), max(dups))\"\n",
      "duration": 5.0
    }
  ]
}

{
